#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<ll, ll>PII
using namespace std;
const int MAXN=5e5+5;
int n,m,T,s[MAXN],e[MAXN],d[MAXN],l,r,maxn=-1;
bool check(int mid)
{
    int sum2=0,sum1=0;
    for(int i=1;i<=n;++i)
	{
        if(s[i]<=l-1)sum1+=(min(l-1,e[i])-s[i])/d[i]+1;
        if(s[i]<=mid)sum2+=(min(mid,e[i])-s[i])/d[i]+1;
    }
	return (sum2-sum1)%2!=0;
}
int main(void){
	scanf("%d",&T);
    while(T--)
	{
        scanf("%d",&n);
        for(int i=1;i<=n;++i)
		{
    		scanf("%d%d%d",s+i,e+i,d+i);
			maxn=max(maxn,e[i]);
        }
		l=1,r=maxn+1;
        while(l<r)
		{
            int mid=(l+r)>>1;
            if(check(mid)) r=mid;
            else l=mid+1;
        }
		if(l==maxn+1)
		{
			printf("There's no weakness.\n");
			continue;
		}
        int sum1=0,sum2=0;
        for(int i=1;i<=n;++i)
		{
            if(s[i]<=l-1) sum1+=(min(l-1,e[i])-s[i])/d[i]+1;
            if(s[i]<=l) sum2+=(min(l,e[i])-s[i])/d[i]+1;
        }
        printf("%d %d\n",l,sum2-sum1);
    }
	return false;
}
